const SPEED_COLOR_GREEN: PIXI.ColorSource = 0x22cc22;
const SPEED_COLOR_YELLOW: PIXI.ColorSource = 0xeedd00;
const SPEED_COLOR_RED: PIXI.ColorSource = 0xff2200;

export class LancerTokenRuler extends foundry.canvas.placeables.tokens.TokenRuler {
  protected override _getSegmentStyle(waypoint: any): any {
    const baseStyle = super._getSegmentStyle(waypoint);
    const speed = this._getTokenSpeed();
    if (speed === null) return baseStyle;

    const cumSpaces = this._getCumulativeSpaces(waypoint);
    return { ...baseStyle, color: this._speedColor(cumSpaces, speed) };
  }

  protected override _getGridHighlightStyle(waypoint: any, offset: any): any {
    const baseStyle = super._getGridHighlightStyle(waypoint, offset);
    const speed = this._getTokenSpeed();
    if (speed === null) return baseStyle;

    const cumSpaces = this._getCumulativeSpaces(waypoint);
    return { ...baseStyle, color: this._speedColor(cumSpaces, speed) };
  }

  protected override _getWaypointStyle(waypoint: any): any {
    const baseStyle = super._getWaypointStyle(waypoint);
    const speed = this._getTokenSpeed();
    if (speed === null) return baseStyle;

    const cumSpaces = this._getCumulativeSpaces(waypoint);
    return { ...baseStyle, color: this._speedColor(cumSpaces, speed) };
  }

  private _getTokenSpeed(): number | null {
    const actor = this.token?.document?.actor;
    if (!actor) return null;
    const speed = (actor.system as any)?.speed;
    if (typeof speed !== "number" || speed <= 0) return null;
    return speed;
  }

  private _getCumulativeSpaces(waypoint: any): number {
    const m = waypoint?.measurement;
    if (!m) return 0;
    if (typeof m.spaces === "number") return m.spaces;
    if (typeof m.distance === "number") return m.distance / (canvas.grid?.distance ?? 1);
    return 0;
  }

  private _speedColor(spaces: number, speed: number): PIXI.ColorSource {
    if (spaces <= speed) return SPEED_COLOR_GREEN;
    if (spaces <= speed * 2) return SPEED_COLOR_YELLOW;
    return SPEED_COLOR_RED;
  }
}
