import type { LancerActor } from "../actor/lancer-actor";
import { getActions, updateActions } from "../action/action-tracker";

interface TurnMoveState {
  totalMove: number;
  boostUsed: boolean;
}

const turnStateMap = new Map<string, TurnMoveState>();

export function resetTurnMovement(actor: LancerActor) {
  turnStateMap.delete(actor.uuid);
}

export function handlePreTokenMovement(tokenDoc: any, change: any): boolean | void {
  if (change.x === undefined && change.y === undefined) return;
  if (!canvas.grid) return;

  const actor = tokenDoc.actor as LancerActor | null;
  if (!actor || !(actor.is_mech() || actor.is_npc())) return;

  const combat = game.combat;
  if (!combat?.active) return;

  const combatant = combat.combatants.find((c: any) => c.actor?.uuid === actor.uuid);
  if (!combatant) return;

  const oldX = tokenDoc.x;
  const oldY = tokenDoc.y;
  const newX = change.x ?? oldX;
  const newY = change.y ?? oldY;

  if (oldX === newX && oldY === newY) return;

  const ray = new Ray({ x: oldX, y: oldY }, { x: newX, y: newY });
  const distance = canvas.grid.measureDistances([{ ray }])[0];
  const spaces = Math.round(distance / canvas.grid.distance);

  if (spaces <= 0) return;

  const speed: number = actor.system.speed;
  const state = turnStateMap.get(actor.uuid) ?? {
    totalMove: 0,
    boostUsed: false,
  };
  const newTotal = state.totalMove + spaces;

  if (newTotal > speed * 2) {
    ui.notifications?.warn("Cannot move beyond maximum distance (red zone).");
    return false;
  }

  if (newTotal > speed) {
    if (state.boostUsed) return;
    const actions = getActions(actor);
    if (!actions || (!actions.quick && !actions.full)) {
      ui.notifications?.warn("No quick action available for Boost movement.");
      return false;
    }
  }
}

export async function handlePostTokenMovement(tokenDoc: any, change: any) {
  if (change.x === undefined && change.y === undefined) return;
  if (!canvas.grid) return;

  const actor = tokenDoc.actor as LancerActor | null;
  if (!actor || !(actor.is_mech() || actor.is_npc())) return;

  const combat = game.combat;
  if (!combat?.active) return;

  const combatant = combat.combatants.find((c: any) => c.actor?.uuid === actor.uuid);
  if (!combatant) return;

  const oldX = tokenDoc.x;
  const oldY = tokenDoc.y;
  const newX = change.x ?? oldX;
  const newY = change.y ?? oldY;

  if (oldX === newX && oldY === newY) return;

  const ray = new Ray({ x: oldX, y: oldY }, { x: newX, y: newY });
  const distance = canvas.grid.measureDistances([{ ray }])[0];
  const spaces = Math.round(distance / canvas.grid.distance);

  if (spaces <= 0) return;

  const speed: number = actor.system.speed;
  const actions = getActions(actor);
  if (!actions) return;

  let state = turnStateMap.get(actor.uuid) ?? {
    totalMove: 0,
    boostUsed: false,
  };

  const newTotal = state.totalMove + spaces;

  if (actions.move > 0) {
    actions.move = Math.max(0, actions.move - spaces);
  }

  if (newTotal > speed && !state.boostUsed) {
    if (actions.full) {
      actions.full = false;
    } else {
      actions.quick = false;
    }
    state.boostUsed = true;
  }

  actions.protocol = false;

  state.totalMove = newTotal;
  turnStateMap.set(actor.uuid, state);

  await updateActions(actor, actions);

  game.action_manager?.update();
}
