import type { DeepPartial } from "fvtt-types/utils";
import { LANCER, friendly_entrytype_name } from "../config";
import { ActivationType, EntryType, NpcFeatureType } from "../enums";
import { modAction } from "../action/action-tracker";
import type { ActionTrackingData } from "../action";
import type { SourceData } from "../source-template";
import { Flow, type FlowState, type Step } from "./flow";
import { LancerFlowState } from "./interfaces";
import type { ActionData } from "../models/bits/action";

export function registerItemUtilSteps(flowSteps: Map<string, Step<any, any> | Flow<any>>) {
  flowSteps.set("checkItemDestroyed", checkItemDestroyed);
  flowSteps.set("checkItemLimited", checkItemLimited);
  flowSteps.set("checkItemCharged", checkItemCharged);
  flowSteps.set("applySelfHeat", applySelfHeat);
  flowSteps.set("updateItemAfterAction", updateItemAfterAction);
  flowSteps.set("deductActionFromTracker", deductActionFromTracker);
}

export async function checkItemDestroyed(
  state: FlowState<LancerFlowState.WeaponRollData | LancerFlowState.TechAttackRollData | LancerFlowState.ActionUseData>
): Promise<boolean> {
  // If this automation option is not enabled, skip the check.
  const { limited_loading, attacks } = game.settings.get(game.system.id, LANCER.setting_automation);
  if (!limited_loading && attacks) return true;
  if (!state.item) return true; // This flow is actor-based, so there is no item to be destroyed.
  if (
    state.item.is_frame() ||
    state.item.is_pilot_weapon() ||
    state.item.is_pilot_gear() ||
    state.item.is_pilot_armor() ||
    state.item.is_talent() ||
    state.item.is_reserve()
  ) {
    return true; // These items can't be destroyed
  }
  if (
    !state.item.is_mech_weapon() &&
    !state.item.is_mech_system() &&
    !state.item.is_weapon_mod() &&
    !state.item.is_npc_feature()
  ) {
    return false;
  }
  if (state.item.system.destroyed) {
    if (
      state.item.is_mech_system() ||
      (state.item.is_npc_feature() && state.item.system.type !== NpcFeatureType.Weapon)
    ) {
      ui.notifications!.warn(`System ${state.item.name} has no remaining uses!`);
    } else {
      ui.notifications!.warn(`Weapon ${state.item.name} has no remaining uses!`);
    }
    return false;
  }
  return true;
}

export async function checkItemLimited(
  state: FlowState<LancerFlowState.WeaponRollData | LancerFlowState.TechAttackRollData | LancerFlowState.ActionUseData>
): Promise<boolean> {
  // If this automation option is not enabled, skip the check.
  const { limited_loading, attacks } = game.settings.get(game.system.id, LANCER.setting_automation);
  if (!limited_loading && attacks) return true;
  if (!state.item) return true; // This flow is actor-based, so there is no item to be destroyed.
  if (state.item.is_talent()) {
    return true; // These items don't support limited uses
  }
  if (
    !state.item.is_mech_weapon() &&
    !state.item.is_mech_system() &&
    !state.item.is_frame() &&
    !state.item.is_weapon_mod() &&
    !state.item.is_pilot_weapon() &&
    !state.item.is_pilot_gear() &&
    !state.item.is_pilot_armor() &&
    !state.item.is_reserve() &&
    !state.item.is_npc_feature()
  ) {
    return false;
  }
  if (state.item.is_frame()) {
    // Frames are special, we need to check for limited on the core system.
    if ((state.item.system.core_system.tags ?? []).some(t => t.is_loading)) {
      // No frames use tags, so none of them track liimited uses.
      return true;
    }
    // The frame is not limited, so we're good.
    return true;
  }
  if (state.item.isLimited() && state.item.system.uses.value <= 0) {
    let iType = friendly_entrytype_name(state.item.type as EntryType);
    ui.notifications!.warn(`${iType} ${state.item.name} has no remaining uses!`);
    return false;
  }
  if (state.item.is_reserve() && state.item.system.consumable) {
    const result = !state.item.system.used; // Reserve items have their own way of tracking limited uses
    if (!result) {
      ui.notifications!.warn(`Reserve ${state.item.name} has already been used!`);
    }
    return result;
  }
  return true;
}

export async function checkItemCharged(
  state: FlowState<LancerFlowState.WeaponRollData | LancerFlowState.TechAttackRollData | LancerFlowState.ActionUseData>
): Promise<boolean> {
  // If this automation option is not enabled, skip the check.
  const { limited_loading, attacks } = game.settings.get(game.system.id, LANCER.setting_automation);
  if (!limited_loading && attacks) return true;
  if (!state.item) return true; // This flow is actor-based, so there is no item to be destroyed.
  if (!state.item.is_npc_feature()) return true; // Recharge only applies to NPC features

  if (state.item.isRecharge() && !state.item.system.charged) {
    if (state.item.system.type !== NpcFeatureType.Weapon) {
      ui.notifications!.warn(`System ${state.item.name} has not recharged!`);
    } else {
      ui.notifications!.warn(`Weapon ${state.item.name} has not recharged!`);
    }
    return false;
  }
  return true;
}

export async function applySelfHeat(
  state: FlowState<
    | LancerFlowState.AttackRollData
    | LancerFlowState.DamageRollData
    | LancerFlowState.WeaponRollData
    | LancerFlowState.TechAttackRollData
    | LancerFlowState.ActionUseData
    | LancerFlowState.SystemUseData
  >,
  options?: {}
): Promise<boolean> {
  if (!state.data) throw new TypeError(`Flow state missing!`);
  let self_heat = 0;

  if ("self_heat" in state.data && state.data.self_heat) {
    const roll = await new Roll(state.data.self_heat).evaluate();
    self_heat = roll.total!;
    state.data.self_heat_result = {
      roll,
      tt: await roll.getTooltip(),
    };
  }

  if (game.settings.get(game.system.id, LANCER.setting_automation).attack_self_heat) {
    if ((state.actor.is_mech() || state.actor.is_npc()) && state.data.type === "damage") {
      let totalHeat = (state.data.overkill_heat ?? 0) + self_heat;
      if (state.actor.system.resistances?.heat) {
        totalHeat = Math.ceil(totalHeat / 2);
      }
      await state.actor.update({
        "system.heat.value": state.actor.system.heat.value + totalHeat,
      });
    }
  }

  return true;
}

export async function updateItemAfterAction(
  state: FlowState<
    | LancerFlowState.WeaponRollData
    | LancerFlowState.TechAttackRollData
    | LancerFlowState.ActionUseData
    | LancerFlowState.SystemUseData
  >,
  options?: {}
): Promise<boolean> {
  if (!state.data) throw new TypeError(`Flow state missing!`);
  const { limited_loading, attacks } = game.settings.get(game.system.id, LANCER.setting_automation);
  if (state.item && limited_loading && attacks) {
    let itemChanges: DeepPartial<SourceData.MechWeapon | SourceData.NpcFeature | SourceData.PilotWeapon> = {};
    if (state.item.isLoading()) itemChanges.loaded = false;
    if (state.item.isLimited()) itemChanges.uses = { value: Math.max(state.item.system.uses.value - 1, 0) };
    if (state.item.is_npc_feature() && state.item.isRecharge())
      (itemChanges as DeepPartial<SourceData.NpcFeature>).charged = false;
    if (state.item.is_reserve() && state.item.system.consumable) {
      (itemChanges as DeepPartial<SourceData.Reserve>).used = true;
    }
    if (Object.keys(itemChanges).length === 0) return true;
    await state.item.update({ system: itemChanges });
  }
  return true;
}

function activationToActionType(activation: ActivationType): keyof ActionTrackingData | null {
  switch (activation) {
    case ActivationType.Quick:
    case ActivationType.QuickTech:
    case ActivationType.Invade:
      return "quick";
    case ActivationType.Full:
    case ActivationType.FullTech:
      return "full";
    case ActivationType.Reaction:
      return "reaction";
    case ActivationType.Protocol:
      return "protocol";
    case ActivationType.Free:
      return "free";
    default:
      return null;
  }
}

function getActivationFromState(
  state: FlowState<
    | LancerFlowState.AttackRollData
    | LancerFlowState.DamageRollData
    | LancerFlowState.WeaponRollData
    | LancerFlowState.TechAttackRollData
    | LancerFlowState.ActionUseData
    | LancerFlowState.SystemUseData
  >
): ActivationType | null {
  if ("action" in state.data && state.data.action) {
    return (state.data.action as ActionData).activation as ActivationType;
  }
  if (state.item) {
    if (state.item.is_mech_weapon()) {
      return state.item.system.active_profile.activation as ActivationType;
    }
    if (
      state.item.is_mech_system() ||
      state.item.is_weapon_mod() ||
      state.item.is_npc_feature() ||
      state.item.is_frame()
    ) {
      const actions = state.item.system.actions;
      if (actions && actions.length > 0) {
        return actions[0].activation as ActivationType;
      }
    }
  }
  return null;
}

export async function deductActionFromTracker(
  state: FlowState<
    | LancerFlowState.AttackRollData
    | LancerFlowState.DamageRollData
    | LancerFlowState.WeaponRollData
    | LancerFlowState.TechAttackRollData
    | LancerFlowState.ActionUseData
    | LancerFlowState.SystemUseData
  >
): Promise<boolean> {
  if (!state.data) throw new TypeError(`Flow state missing!`);
  if (!game.settings.get(game.system.id, LANCER.setting_automation).attack_self_heat) return true;
  if (!state.actor.is_mech() && !state.actor.is_npc()) return true;

  const activation = getActivationFromState(state);
  if (!activation) return true;

  const actionType = activationToActionType(activation);
  if (!actionType) return true;

  await modAction(state.actor, true, actionType);
  return true;
}
